-- ─── CATEGORY 1 — Günlük Konuşma ────────────────────────────────────────────

INSERT INTO sentences (category_id, text_tr, text_en, text_sv, text_de, keywords_tr, keywords_en, keywords_sv, keywords_de, difficulty, is_free, sort_order) VALUES

-- Beginner
(1, '**Bu arada**, yarın serbest misin?', '**By the way**, are you free tomorrow?', '**Förresten**, är du ledig imorgon?', '**Übrigens**, bist du morgen frei?', '["bu arada"]', '["by the way"]', '["förresten"]', '["übrigens"]', 'beginner', true, 1),
(1, '**Yani**, bunu gerçekten söylüyor musun?', '**I mean**, are you really saying that?', '**Alltså**, menar du verkligen det?', '**Ich meine**, sagst du das wirklich?', '["yani"]', '["I mean"]', '["alltså"]', '["ich meine"]', 'beginner', true, 2),
(1, '**Biliyor musun**, bu tam aradığım şey.', '**You know what**, this is exactly what I needed.', '**Vet du vad**, det här är precis vad jag behövde.', '**Weißt du was**, das ist genau das, was ich gebraucht habe.', '["biliyor musun"]', '["you know what"]', '["vet du vad"]', '["weißt du was"]', 'beginner', true, 3),
(1, '**Dürüst olmak gerekirse**, bu film pek hoşuma gitmedi.', '**To be honest**, I didn''t really enjoy this film.', '**För att vara ärlig**, tyckte jag inte så mycket om den här filmen.', '**Ehrlich gesagt** hat mir dieser Film nicht wirklich gefallen.', '["dürüst olmak gerekirse"]', '["to be honest"]', '["för att vara ärlig"]', '["ehrlich gesagt"]', 'beginner', true, 4),
(1, '**Her şeyden önce**, teşekkür etmek istiyorum.', '**First of all**, I want to say thank you.', '**Först och främst** vill jag säga tack.', '**Zunächst einmal** möchte ich Danke sagen.', '["her şeyden önce"]', '["first of all"]', '["först och främst"]', '["zunächst einmal"]', 'beginner', true, 5),
(1, 'Gelmeseydin bile **en azından** bir mesaj atabilirdin.', 'Even if you couldn''t come, you could have **at least** sent a message.', 'Även om du inte kunde komma kunde du **åtminstone** ha skickat ett meddelande.', 'Auch wenn du nicht kommen konntest, hättest du **zumindest** eine Nachricht schicken können.', '["en azından"]', '["at least"]', '["åtminstone"]', '["zumindest"]', 'beginner', true, 6),
(1, 'Bunu **hemen** halledelim.', 'Let''s take care of this **right away**.', 'Låt oss ta hand om det här **genast**.', 'Lass uns das **sofort** erledigen.', '["hemen"]', '["right away"]', '["genast"]', '["sofort"]', 'beginner', true, 7),
(1, '**Kesinlikle** yardım edebilirim.', 'I can **for sure** help you with that.', 'Jag kan **definitivt** hjälpa dig med det.', 'Ich kann dir dabei **auf jeden Fall** helfen.', '["kesinlikle"]', '["for sure"]', '["definitivt"]', '["auf jeden Fall"]', 'beginner', true, 8),
(1, 'Rahatsız ediyor muyum? — **Hiç de değil**!', 'Am I bothering you? — **Not at all**!', 'Stör jag dig? — **Inte alls**!', 'Störe ich dich? — **Überhaupt nicht**!', '["hiç de değil"]', '["not at all"]', '["inte alls"]', '["überhaupt nicht"]', 'beginner', true, 9),
(1, '**Tabii ki** sana yardım ederim, sor istediğini.', '**Of course** I''ll help you, just ask.', '**Självklart** hjälper jag dig, fråga bara.', '**Natürlich** helfe ich dir, frag einfach.', '["tabii ki"]', '["of course"]', '["självklart"]', '["natürlich"]', 'beginner', true, 10),

-- Intermediate
(1, '**Sonuçta**, herkes hata yapar.', '**After all**, everyone makes mistakes.', '**Trots allt** gör alla misstag.', '**Schließlich** macht jeder Fehler.', '["sonuçta"]', '["after all"]', '["trots allt"]', '["schließlich"]', 'intermediate', true, 11),
(1, '**Nasıl oluyor** da bu kadar hızlı öğrenebiliyorsun?', '**How come** you can learn so fast?', '**Hur kommer det sig** att du kan lära dig så snabbt?', '**Wie kommt es**, dass du so schnell lernen kannst?', '["nasıl oluyor"]', '["how come"]', '["hur kommer det sig"]', '["wie kommt es"]', 'intermediate', true, 12),
(1, '**Peki ya** sen, ne düşünüyorsun?', '**What about** you, what do you think?', '**Vad sägs om** dig, vad tycker du?', '**Was ist mit** dir, was denkst du?', '["peki ya"]', '["what about"]', '["vad sägs om"]', '["was ist mit"]', 'intermediate', true, 13),
(1, '**Bana gelince**, evde kalmayı tercih ederim.', '**As for me**, I prefer to stay home.', '**Vad gäller mig** föredrar jag att stanna hemma.', '**Was mich betrifft**, bleibe ich lieber zu Hause.', '["bana gelince"]', '["as for me"]', '["vad gäller mig"]', '["was mich betrifft"]', 'intermediate', true, 14),
(1, 'Bir şey sorabilir miyim? — **Buyurun**!', 'May I ask something? — **Go ahead**!', 'Får jag fråga något? — **Varsågod**!', 'Darf ich etwas fragen? — **Bitte sehr**!', '["buyurun"]', '["go ahead"]', '["varsågod"]', '["bitte sehr"]', 'intermediate', true, 15),
(1, 'Geç kaldım, özür dilerim. — **Boşver**, önemli değil.', 'I''m late, I''m sorry. — **Never mind**, it''s okay.', 'Jag är sen, förlåt. — **Strunta i det**, det är okej.', 'Ich bin spät, tut mir leid. — **Macht nichts**, ist okay.', '["boşver"]', '["never mind"]', '["strunta i det"]', '["macht nichts"]', 'intermediate', true, 16),
(1, '**Bir dakika**, telefonum nerede acaba?', '**Hold on**, where is my phone?', '**Vänta lite**, var är min telefon?', '**Einen Moment**, wo ist mein Handy?', '["bir dakika"]', '["hold on"]', '["vänta lite"]', '["einen Moment"]', 'intermediate', true, 17),
(1, '**Acele etme**, hep birlikte bekliyoruz.', '**Take your time**, we''re all waiting.', '**Ta dig tid**, vi väntar alla.', '**Lass dir Zeit**, wir warten alle.', '["acele etme"]', '["take your time"]', '["ta dig tid"]', '["lass dir Zeit"]', 'intermediate', true, 18),
(1, '**Aslında**, sana bir şey söylemek istiyordum.', '**Actually**, I''ve been meaning to tell you something.', '**Faktiskt** har jag velat berätta något för dig.', '**Eigentlich** wollte ich dir schon länger etwas sagen.', '["aslında"]', '["actually"]', '["faktiskt"]', '["eigentlich"]', 'intermediate', true, 19),
(1, 'Çok zor görünüyor, **gerçekte** ise oldukça kolay.', 'It looks difficult, but **in fact** it''s quite easy.', 'Det ser svårt ut, men **i själva verket** är det ganska enkelt.', 'Es sieht schwierig aus, aber **tatsächlich** ist es ziemlich einfach.', '["gerçekte"]', '["in fact"]', '["i själva verket"]', '["tatsächlich"]', 'intermediate', true, 20),

-- Advanced
(1, 'Bu durum **bir nevi** garip, değil mi?', 'This situation is **kind of** weird, isn''t it?', 'Den här situationen är **lite** konstig, eller hur?', 'Diese Situation ist **irgendwie** seltsam, oder?', '["bir nevi"]', '["kind of"]', '["lite"]', '["irgendwie"]', 'advanced', true, 21),
(1, '**Şaşılacak bir şey yok** ki yoruldun, tüm gün çalıştın.', '**No wonder** you''re tired, you worked all day.', '**Inte konstigt** att du är trött, du jobbade hela dagen.', '**Kein Wunder**, dass du müde bist, du hast den ganzen Tag gearbeitet.', '["şaşılacak bir şey yok"]', '["no wonder"]', '["inte konstigt"]', '["kein Wunder"]', 'advanced', true, 22),
(1, 'Nereye gidiyoruz? — **Sana kalmış**, sen seç.', 'Where are we going? — **It''s up to you**, you choose.', 'Vart ska vi? — **Det är upp till dig**, du väljer.', 'Wohin fahren wir? — **Das liegt bei dir**, du entscheidest.', '["sana kalmış"]', '["it''s up to you"]', '["det är upp till dig"]', '["das liegt bei dir"]', 'advanced', true, 23),
(1, '**Uzun zamandır görüşmüyorduk**! Nasılsın?', '**Long time no see**! How have you been?', '**Länge sedan sist**! Hur har du haft det?', '**Lange nicht gesehen**! Wie geht es dir?', '["uzun zamandır görüşmüyorduk"]', '["long time no see"]', '["länge sedan sist"]', '["lange nicht gesehen"]', 'advanced', true, 24),
(1, 'Özür dilerim, zaman aldı. — **Büyük bir şey değil**, merak etme.', 'Sorry it took so long. — **No big deal**, don''t worry.', 'Förlåt att det tog tid. — **Ingen stor sak**, oroa dig inte.', 'Es tut mir leid, dass es so lange dauerte. — **Keine große Sache**, keine Sorge.', '["büyük bir şey değil"]', '["no big deal"]', '["ingen stor sak"]', '["keine große Sache"]', 'advanced', true, 25),
(1, 'Bir şemsiye al, **her ihtimale karşı**.', 'Take an umbrella, **just in case**.', 'Ta ett paraply, **för säkerhets skull**.', 'Nimm einen Regenschirm mit, **für alle Fälle**.', '["her ihtimale karşı"]', '["just in case"]', '["för säkerhets skull"]', '["für alle Fälle"]', 'advanced', true, 26),
(1, 'Pahalı, **bunun yanı sıra** çok uzakta da.', 'It''s expensive, **besides** it''s very far away.', 'Det är dyrt, **dessutom** är det väldigt långt bort.', 'Es ist teuer, **außerdem** ist es sehr weit entfernt.', '["bunun yanı sıra"]', '["besides"]', '["dessutom"]', '["außerdem"]', 'advanced', true, 27),
(1, '**Her neyse**, konuya dönelim.', '**Anyway**, let''s get back to the topic.', '**Hur som helst**, låt oss komma tillbaka till ämnet.', '**Jedenfalls**, lass uns zum Thema zurückkehren.', '["her neyse"]', '["anyway"]', '["hur som helst"]', '["jedenfalls"]', 'advanced', true, 28),
(1, '**Sanırım** haklısın, düşünmem gerekiyor.', '**I suppose** you''re right, I need to think about it.', '**Jag antar** att du har rätt, jag behöver tänka på det.', '**Ich nehme an**, du hast recht, ich muss darüber nachdenken.', '["sanırım"]', '["I suppose"]', '["jag antar"]', '["ich nehme an"]', 'advanced', true, 29),
(1, '**Ne demek istiyorsun** tam olarak, anlamadım.', '**What do you mean** exactly? I didn''t get it.', '**Vad menar du** exakt? Jag förstod inte.', '**Was meinst du** genau? Ich habe das nicht verstanden.', '["ne demek istiyorsun"]', '["what do you mean"]', '["vad menar du"]', '["was meinst du"]', 'advanced', true, 30);

