INSERT INTO sentences (category_id, text_tr, text_en, text_sv, text_de, keywords_tr, keywords_en, keywords_sv, keywords_de, difficulty, is_free, sort_order) VALUES

-- Beginner
(2, 'Araştırıp **size geri döneceğim**.', 'I''ll look into it and **get back to you**.', 'Jag ska undersöka det och **återkomma till dig**.', 'Ich werde das prüfen und mich **bei Ihnen melden**.', '["size geri döneceğim"]', '["get back to you"]', '["återkomma till dig"]', '["bei Ihnen melden"]', 'beginner', true, 31),
(2, 'Bu konuyu **takip etmem** gerekiyor.', 'I need to **follow up** on this matter.', 'Jag behöver **följa upp** den här frågan.', 'Ich muss dieses Thema **nachverfolgen**.', '["takip etmem"]', '["follow up"]', '["följa upp"]', '["nachverfolgen"]', 'beginner', true, 32),
(2, 'Haftaya **kısaca görüşelim**.', 'Let''s **touch base** next week.', 'Låt oss **höras av** nästa vecka.', 'Lass uns nächste Woche **kurz in Kontakt treten**.', '["kısaca görüşelim"]', '["touch base"]', '["höras av"]', '["kurz in Kontakt treten"]', 'beginner', true, 33),
(2, 'Bunu yaparken **aklında tut**.', 'Please **keep in mind** while you do this.', 'Ha det i **åtanke** när du gör det.', 'Bitte **behalte das im Hinterkopf**, wenn du das tust.', '["aklında tut"]', '["keep in mind"]', '["åtanke"]', '["behalte das im Hinterkopf"]', 'beginner', true, 34),
(2, 'Raporu **en kısa sürede** gönderebilir misin?', 'Can you send the report **as soon as possible**?', 'Kan du skicka rapporten **så snart som möjligt**?', 'Kannst du den Bericht **so schnell wie möglich** schicken?', '["en kısa sürede"]', '["as soon as possible"]', '["så snart som möjligt"]', '["so schnell wie möglich"]', 'beginner', true, 35),
(2, 'Projeyle **ilerleyelim**.', 'Let''s **move forward** with the project.', 'Låt oss **gå vidare** med projektet.', 'Lass uns mit dem Projekt **vorankommen**.', '["ilerleyelim"]', '["move forward"]', '["gå vidare"]', '["vorankommen"]', 'beginner', true, 36),
(2, 'Müşteriyle **iletişime geçmem** gerekiyor.', 'I need to **reach out** to the client.', 'Jag behöver **kontakta** kunden.', 'Ich muss mich mit dem Kunden **in Verbindung setzen**.', '["iletişime geçmem"]', '["reach out"]', '["kontakta"]', '["in Verbindung setzen"]', 'beginner', true, 37),
(2, 'Bu sorunu **araştıracağım**.', 'I''ll **look into** this problem.', 'Jag ska **undersöka** det här problemet.', 'Ich werde dieses Problem **untersuchen**.', '["araştıracağım"]', '["look into"]', '["undersöka"]', '["untersuchen"]', 'beginner', true, 38),
(2, 'Toplantıyı **bitirelim** artık.', 'Let''s **wrap up** the meeting now.', 'Låt oss **avsluta** mötet nu.', 'Lass uns die Besprechung jetzt **abschließen**.', '["bitirelim"]', '["wrap up"]', '["avsluta"]', '["abschließen"]', 'beginner', true, 39),
(2, 'Yeni bir çözüm **bulmamız** lazım.', 'We need to **come up with** a new solution.', 'Vi behöver **hitta på** en ny lösning.', 'Wir müssen eine neue Lösung **finden**.', '["bulmamız"]', '["come up with"]', '["hitta på"]', '["finden"]', 'beginner', true, 40),

-- Intermediate
(2, 'Bu meseleyi ben **halledeceğim**.', 'I''ll **take care of** this issue.', 'Jag ska **ta hand om** det här problemet.', 'Ich werde mich um diese Angelegenheit **kümmern**.', '["halledeceğim"]', '["take care of"]', '["ta hand om"]', '["kümmern"]', 'intermediate', true, 41),
(2, 'Raporun durumunu **kontrol edeyim**.', 'Let me **check in** on the report status.', 'Låt mig **kolla av** rapportens status.', 'Lass mich den Status des Berichts **überprüfen**.', '["kontrol edeyim"]', '["check in"]', '["kolla av"]', '["überprüfen"]', 'intermediate', true, 42),
(2, 'Sunumu birlikte **gözden geçirelim**.', 'Let''s **go over** the presentation together.', 'Låt oss **gå igenom** presentationen tillsammans.', 'Lass uns die Präsentation gemeinsam **durchgehen**.', '["gözden geçirelim"]', '["go over"]', '["gå igenom"]', '["durchgehen"]', 'intermediate', true, 43),
(2, 'Bu problemi nasıl **çözeceğiz**?', 'How are we going to **deal with** this problem?', 'Hur ska vi **hantera** det här problemet?', 'Wie werden wir mit diesem Problem **umgehen**?', '["çözeceğiz"]', '["deal with"]', '["hantera"]', '["umgehen"]', 'intermediate', true, 44),
(2, 'Bütçe konusunu toplantıda **gündeme getirmeliyiz**.', 'We should **bring up** the budget topic in the meeting.', 'Vi bör **ta upp** budgetfrågan på mötet.', 'Wir sollten das Budgetthema im Meeting **ansprechen**.', '["gündeme getirmeliyiz"]', '["bring up"]', '["ta upp"]', '["ansprechen"]', 'intermediate', true, 45),
(2, 'Araştırmayı bu hafta **tamamlayacağız**.', 'We''ll **carry out** the research this week.', 'Vi ska **genomföra** forskningen den här veckan.', 'Wir werden die Forschung diese Woche **durchführen**.', '["tamamlayacağız"]', '["carry out"]', '["genomföra"]', '["durchführen"]', 'intermediate', true, 46),
(2, 'Seni **gelişmelerden haberdar** edeceğim.', 'I''ll keep you **in the loop**.', 'Jag håller dig **informerad**.', 'Ich werde dich **auf dem Laufenden** halten.', '["gelişmelerden haberdar"]', '["in the loop"]', '["informerad"]', '["auf dem Laufenden"]', 'intermediate', true, 47),
(2, 'Bu konuda hepimiz **aynı fikirde miyiz**?', 'Are we all **on the same page** about this?', 'Är vi alla **överens** om det här?', 'Sind wir alle in dieser Sache **einer Meinung**?', '["aynı fikirde"]', '["on the same page"]', '["överens"]', '["einer Meinung"]', 'intermediate', true, 48),
(2, '**Önceden uyarmak** istedim: sistem bakımda olacak.', 'Just a **heads up**: the system will be down for maintenance.', 'Bara en **förhandsvarning**: systemet kommer att vara nere för underhåll.', 'Nur zur **Vorab-Information**: Das System wird für Wartungsarbeiten ausfallen.', '["önceden uyarmak"]', '["heads up"]', '["förhandsvarning"]', '["Vorab-Information"]', 'intermediate', true, 49),
(2, 'Bu projede sen **öncülük et**.', 'You should **take the lead** on this project.', 'Du bör **leda** det här projektet.', 'Du solltest bei diesem Projekt **die Führung übernehmen**.', '["öncülük et"]', '["take the lead"]', '["leda"]', '["die Führung übernehmen"]', 'intermediate', true, 50),

-- Advanced
(2, 'Yeni dönemi resmi olarak **başlatalım**.', 'Let''s officially **kick off** the new quarter.', 'Låt oss officiellt **kicka igång** det nya kvartalet.', 'Lass uns das neue Quartal offiziell **einleiten**.', '["başlatalım"]', '["kick off"]', '["kicka igång"]', '["einleiten"]', 'advanced', true, 51),
(2, 'Anlaşmayı **onaylayabilir misin**?', 'Can you **sign off** on the agreement?', 'Kan du **godkänna** avtalet?', 'Kannst du die Vereinbarung **genehmigen**?', '["onaylayabilir misin"]', '["sign off"]', '["godkänna"]', '["genehmigen"]', 'advanced', true, 52),
(2, 'Beni **bilgilendirebilir misin**?', 'Can you **fill me in**?', 'Kan du **informera** mig?', 'Kannst du mich **informieren**?', '["bilgilendirebilir misin"]', '["fill me in"]', '["informera"]', '["informieren"]', 'advanced', true, 53),
(2, '**Bundan sonra** haftalık raporlar paylaşılacak.', '**Going forward**, weekly reports will be shared.', '**Framöver** kommer veckorapporter att delas.', '**Zukünftig** werden wöchentliche Berichte geteilt.', '["bundan sonra"]', '["going forward"]', '["framöver"]', '["zukünftig"]', 'advanced', true, 54),
(2, '**Müsait olduğunuzda** bir görüşme ayarlayalım.', 'Let''s arrange a call **at your earliest convenience**.', 'Låt oss boka ett samtal **när det passar dig**.', 'Lass uns ein Gespräch **nach Ihrer Verfügbarkeit** vereinbaren.', '["müsait olduğunuzda"]', '["at your earliest convenience"]', '["när det passar dig"]', '["nach Ihrer Verfügbarkeit"]', 'advanced', true, 55),
(2, 'Yeni sistemi **kurmamız** gerekiyor.', 'We need to **set up** the new system.', 'Vi behöver **installera** det nya systemet.', 'Wir müssen das neue System **einrichten**.', '["kurmamız"]', '["set up"]', '["installera"]', '["einrichten"]', 'advanced', true, 56),
(2, 'Projeyi iki günde **teslim etmem** gerekiyor.', 'I need to **turn this around** in two days.', 'Jag behöver **slutföra** det här på två dagar.', 'Ich muss das in zwei Tagen **abwickeln**.', '["teslim etmem"]', '["turn this around"]', '["slutföra"]', '["abwickeln"]', 'advanced', true, 57),
(2, 'Neden bu kadar zaman aldığını **anlamamız** lazım.', 'We need to **figure out** why this is taking so long.', 'Vi måste **lista ut** varför det här tar så lång tid.', 'Wir müssen **herausfinden**, warum das so lange dauert.', '["anlamamız"]', '["figure out"]', '["lista ut"]', '["herausfinden"]', 'advanced', true, 58),
(2, 'Bunu müdüre **onaylatmam** gerekiyor.', 'I need to **run this by** the manager first.', 'Jag behöver **stämma av** detta med chefen först.', 'Ich muss das zuerst mit dem Manager **absprechen**.', '["onaylatmam"]', '["run this by"]', '["stämma av"]', '["absprechen"]', 'advanced', true, 59),
(2, 'Sunumu birlikte **hazırlayalım**.', 'Let''s **put together** the presentation.', 'Låt oss **sätta ihop** presentationen.', 'Lass uns die Präsentation **zusammenstellen**.', '["hazırlayalım"]', '["put together"]', '["sätta ihop"]', '["zusammenstellen"]', 'advanced', true, 60);

-- ─── CATEGORY 3 — Phrasal Verbs ─────────────────────────────────────────────

INSERT INTO sentences (category_id, text_tr, text_en, text_sv, text_de, keywords_tr, keywords_en, keywords_sv, keywords_de, difficulty, is_free, sort_order) VALUES

-- Beginner
(3, 'Hiç **vazgeçme**, yapabilirsin!', 'Never **give up**, you can do it!', 'Ge aldrig **upp**, du kan göra det!', 'Gib niemals **auf**, du schaffst das!', '["vazgeçme"]', '["give up"]', '["ge upp"]', '["aufgeben"]', 'beginner', false, 61),
(3, 'Param **bitti**, ATM''ye gitmem lazım.', 'I **ran out of** money, I need to find an ATM.', 'Jag **fick slut på** pengar, jag behöver hitta en bankomat.', 'Mir ist das Geld **ausgegangen**, ich muss einen Geldautomaten finden.', '["bitti"]', '["ran out of"]', '["fick slut på"]', '["ausgegangen"]', 'beginner', false, 62),
(3, 'Seni havalimanından **alacağım**.', 'I''ll **pick you up** from the airport.', 'Jag ska **hämta** dig på flygplatsen.', 'Ich hole dich vom Flughafen **ab**.', '["alacağım"]', '["pick up"]', '["hämta"]', '["abholen"]', 'beginner', false, 63),
(3, 'Bu tatili dört gözle **bekliyorum**.', 'I''m really **looking forward to** this holiday.', 'Jag ser verkligen **fram emot** den här semestern.', 'Ich **freue mich wirklich** auf diesen Urlaub.', '["bekliyorum"]', '["looking forward to"]', '["fram emot"]', '["freue mich"]', 'beginner', false, 64),
(3, 'İnternette ilginç bir makaleye **rastladım**.', 'I **came across** an interesting article online.', 'Jag **stötte på** en intressant artikel på nätet.', 'Ich bin online auf einen interessanten Artikel **gestoßen**.', '["rastladım"]', '["came across"]', '["stötte på"]', '["gestoßen"]', 'beginner', false, 65),
